class ConciseCoT(dspy.Signature):
    """Fast reasoning without verbose CoT."""
    question: str = dspy.InputField()
    reasoning: str = dspy.OutputField(desc="1-2 sentences max, no fluff")
    answer: str = dspy.OutputField(desc="Direct final answer")

class FastCoTModule(dspy.Module):
    def __init__(self):
        super().__init__()
        self.generate_reasoning = dspy.ChainOfThought(ConciseCoT)

    def forward(self, question):
        pred = self.generate_reasoning(question=question)
        return dspy.Prediction(answer=pred.answer)

# Replace verbose CoT
fast_cot = FastCoTModule()
result = fast_cot(question="Solve: 15*3+7")
# Reduces tokens by 60% vs standard CoT

from dspy.teleprompt import BootstrapFewShot

class BudgetOptimizer(BootstrapFewShot):
    def __init__(self, max_tokens_per_trial=1500, max_trials=20, **kwargs):
        super().__init__(**kwargs)
        self.max_tokens = max_tokens_per_trial
        self.max_trials = max_trials

    def improve_from_examples(self, *args, **kwargs):
        # Truncate examples to fit token budget
        for ex in args:
            if hasattr(ex, 'inputs'):
                ex.inputs = {k: v[:200] for k, v in ex.inputs.items()}

        pred = super().improve_from_examples(*args, **kwargs)

        # Enforce concise outputs
        if len(pred.completions) > self.max_tokens:
            pred.completions = pred.completions[:self.max_tokens]

        return pred

# Usage - 3x faster optimization
optimizer = BudgetOptimizer(
    metric=my_metric,
    max_bootstrapped_demos=2,  # Fewer demos
    max_tokens_per_trial=1000,
    max_trials=15
)
optimized = optimizer.compile(module, trainset[:50])

