import dspy
import vex

from dspy.teleprompt import BootstrapFewShot

# Your DSPy agent
class Agent(dspy.Module):
    def __init__(self):
        super().__init__()
        self.retrieve = dspy.Retrieve(k=3)
        self.cot = dspy.ChainOfThought("context, question -> answer")

    def forward(self, question):
        context = self.retrieve(question=question).passages
        return self.cot(question=question, context=context)

# Vex auto-instrumentation
@vex.verify(
    latency_threshold_ms=1500,
    token_threshold=1200,
    metric='agent_accuracy'
)
def optimize_agent(trainset):
    agent = Agent()
    optimizer = BootstrapFewShot(metric=lambda ex, pred, trace: ex.label == pred.answer)
    return optimizer.compile(agent, trainset=trainset)

